def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 10:
            for a in range(1, 8):
                for b in range(1, a+5):
                    val = ((ratio - 9) ** 4) / (a * b + 1)
                    priority += val * np.sin(ratio * a / (b+0.5)) * np.cos(ratio * b / (a+0.7))
            priority += np.exp(ratio - 9) * np.cos(ratio * 2.3) ** 1.8
        elif 7 < ratio <= 10:
            for x in range(1, 5):
                for y in range(1, x + 4):
                    val = np.tanh(((ratio - 7) ** 3) / (y + 0.3)) * np.sin(ratio * y) * 1.5
                    priority += val
            priority += np.log(ratio + 1) * 12 - np.tanh(ratio - 7) * 3
        elif 5 <= ratio <= 7:
            s = 0.0
            for n in range(1, 14):
                s += ((ratio - 5) ** n) / (n * 2.1) * np.cos(n * ratio * 1.5)
            priority = s * np.sin(8 * ratio) - np.log(ratio) * 7 + np.tanh(5 * (7 - ratio)) * 2
            for m in range(1,4):
                priority += np.exp(-m*ratio) * np.sin(m*i*0.7)
        elif 3 <= ratio < 5:
            priority = 0
            for p in range(1, 6):
                for q in range(1, p + 3):
                    factor = ((5 - ratio) ** p) / (q**1.5 + 0.4)
                    priority += factor * np.cos(ratio * q * 1.1)
            if bin_cap < item * 1.5:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 6
            else:
                priority -= np.exp(-2 * ratio) * 3
        elif 1 <= ratio < 3:
            s = 0.0
            for k in range(1, 20):
                s += ((3 - ratio) ** k) / (k * 3) * np.sin(k * ratio * 2)
            priority = s + np.log1p(bin_cap) * 2
            if i % 2 == 0:
                priority += np.sin(ratio * i * 2.3) * 1.2
            else:
                priority -= np.cos(ratio * i * 1.7) * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for r in range(1, 12):
                s += ((1 - ratio) ** r) / (r**2 + 0.7)
            priority = s * np.cos(10 * ratio) + np.exp(-ratio * ratio) * 4
            for j in range(1, 5):
                if (i + j) % 2 == 0:
                    priority += np.sin(ratio * j * 3) / j
                else:
                    priority -= np.cos(ratio * j * 2) / (j**1.1)
            if bin_cap > item * 1.3:
                priority -= np.sqrt(bin_cap - item) * 2.5
            else:
                priority += np.log1p(item * bin_cap) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0.0
            for w in range(1, 18):
                s += ((0.5 - ratio) ** w) / (w * 5) * np.sin(w * item * 1.3)
            priority = s + 3 / (bin_cap + 1)
            if int(item * 2.1) % 3 == 0:
                priority *= 2
            else:
                priority /= 2
            for z in range(1, 9):
                priority += ((0.5 - ratio) ** z) / (z * 7) * np.cos(item * z * 0.9)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 0.8)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 0.9) % 4 == 0:
                priority *= 2.7
            else:
                priority /= 2.7
            if bin_cap < item * 0.12:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 8) * np.sin(item * v * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.65
        priorities[i] = priority
    return priorities
